import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    public void testPrintCreatesCSVPrinter() throws IOException {
        try (MockedConstruction<OutputStreamWriter> mockedOutputStreamWriter = mockConstruction(OutputStreamWriter.class);
             MockedConstruction<CSVPrinter> mockedCSVPrinter = mockConstruction(CSVPrinter.class,
                     (mock, context) -> {
                         // no-op
                     })) {

            CSVPrinter printer = csvFormat.print(mockFile, charset);

            assertNotNull(printer);
            // Verify that OutputStreamWriter was constructed with FileOutputStream and charset
            assertEquals(1, mockedOutputStreamWriter.constructed().size());
            assertEquals(1, mockedCSVPrinter.constructed().size());
        }
    }

    @Test
    public void testPrintThrowsIOException() {
        // To simulate IOException, we mock OutputStreamWriter constructor to throw
        try (MockedConstruction<OutputStreamWriter> mockedOutputStreamWriter = mockConstruction(OutputStreamWriter.class,
                (mock, context) -> {
                    throw new IOException("Simulated IOException");
                })) {

            IOException thrown = assertThrows(IOException.class, () -> {
                csvFormat.print(mockFile, charset);
            });
            assertEquals("Simulated IOException", thrown.getMessage());
        }
    }
}
